        compressor_inverter: { efficiency: 0.92, surgeFactor: 2.0, powerFactor: 0.85, startMethod: 'vfd', hint: 'Inverter compressor: smooth VFD start, only 2x surge. Most energy-efficient. Ideal for PV systems.' },
