        compressor_old: { efficiency: 0.75, surgeFactor: 5.0, powerFactor: 0.65, startMethod: 'dol', hint: 'Old compressor (>7 years): worn bearings increase inrush to 5x+. Consider replacing for PV compatibility.' },
