            if (decisionStrategy.status === 'warn')
                strategyPenalty += 4;
            else if (decisionStrategy.status === 'fail')
                strategyPenalty += 10;
            if (!decisionStrategy.isIntentAligned)
                strategyPenalty += 3;
            if (!decisionStrategy.isSystemTypeAligned)
                strategyPenalty += 3;
