    populatePlantScopingOptions() {
        const mappings = [
            {
                selectId: 'plantScopeMode',
                entries: Object.entries(this.getPlantScopeModes()),
                fallback: 'auto'
            },
            {
                selectId: 'distributionTopologyMode',
                entries: Object.entries(this.getDistributionTopologyModes()),
                fallback: 'auto'
            },
            {
                selectId: 'interconnectionScopeMode',
                entries: Object.entries(this.getInterconnectionScopeModes()),
                fallback: 'auto'
            }
        ];

        mappings.forEach(({ selectId, entries, fallback }) => {
            const select = document.getElementById(selectId);
            if (!select) return;
            const previous = select.value;
            select.innerHTML = entries.map(([key, definition]) => `
                <option value="${this.escapeHtml(key)}">${this.escapeHtml(definition.label)}</option>
            `).join('');
            const nextValue = entries.some(([key]) => key === previous) ? previous : fallback;
            select.value = nextValue;
        });

        this.refreshPlantScopingUI();
    },

