        assignValue('supplierRefreshWindowDays', DEFAULTS.PROPOSAL_PRICING.quoteFreshnessDefaults?.refreshWindowDays || 14);
        assignValue('proposalIncludedScope', (template.includedScope || DEFAULTS.PROPOSAL_PRICING.defaultLists.includedScope).join('\n'));
        assignValue('proposalExclusions', (template.exclusions || DEFAULTS.PROPOSAL_PRICING.defaultLists.exclusions).join('\n'));
        assignValue('proposalNextSteps', (template.nextSteps || DEFAULTS.PROPOSAL_PRICING.defaultLists.nextSteps).join('\n'));

        assignValue('proposalCompanyName', installerIdentity.company);
        assignValue('proposalContactName', installerIdentity.contactName);
        assignValue('proposalContactPhone', installerIdentity.contactPhone);
        assignValue('proposalContactEmail', installerIdentity.contactEmail);
        assignValue('proposalBrandAccent', installerIdentity.brandAccent);
        assignValue('proposalIssuerTagline', installerIdentity.issuerTagline);
        assignValue('proposalFooterNote', installerIdentity.footerNote);
        this.setProposalBrandLogoState({
            name: installerIdentity.brandLogoName,
            dataUrl: installerIdentity.brandLogoDataUrl
        });
        assignValue('proposalClientName', '');
        assignValue('proposalSiteName', '');
        assignValue('proposalQuoteReference', '');
        assignValue('proposalIssueDate', today);
        assignValue('proposalProfileLabel', '');
        assignValue('proposalReleaseTemplateSelect', '');
