        assignValue('surveyNotes', '');
        assignChecked('surveyStructureConfirmed', false);
        assignChecked('surveyCableRouteConfirmed', false);
        assignChecked('surveyEarthingConfirmed', false);
        assignChecked('surveyExclusionsReviewed', false);
        assignChecked('surveyBudgetAligned', false);
        assignChecked('surveyUtilityReviewed', false);
        assignValue('supplierQuoteImportText', '');

        this.refreshBusinessContextUI();
        this.refreshCommercialArchitectureUI();
        this.renderCommercialPresetPreview();
        this.populateBusinessMachineOptions();
        this.onPhaseTypeChange();
        this.updateAudienceMode();
        this.toggleManualMode();
        this.onSystemTypeChange();
        this.onBatteryChemistryChange();
        this.initializeProposalContextDefaults();

        LoadEngine.appliances = JSON.parse(JSON.stringify(template.appliances || []));
        this.editingIndex = null;
        this.renderApplianceList();
        this.validatePanelSpecs();
        this.renderSavedProjects();
        this.renderProjectTemplatePreview();
        this.renderEquipmentLibraryPreview();
        this.renderSupplierPricingPreview();
        this.renderSupplierQuoteFreshnessPreview();
        this.renderSupplierRefreshRequestPreview();
